-- Disable RLS on all main tables to restore functionality
ALTER TABLE users DISABLE ROW LEVEL SECURITY;
ALTER TABLE clients DISABLE ROW LEVEL SECURITY;
ALTER TABLE policies DISABLE ROW LEVEL SECURITY;
ALTER TABLE installments DISABLE ROW LEVEL SECURITY;
ALTER TABLE collections DISABLE ROW LEVEL SECURITY;
ALTER TABLE activity_logs DISABLE ROW LEVEL SECURITY;
ALTER TABLE targets DISABLE ROW LEVEL SECURITY;

-- Drop all policies to start fresh
DROP POLICY IF EXISTS "users_public_read" ON users;
DROP POLICY IF EXISTS "users_auth_insert" ON users;
DROP POLICY IF EXISTS "users_auth_update" ON users;
DROP POLICY IF EXISTS "users_auth_delete" ON users;
